#!/usr/bin/env bash
# tracking-programming.sh — Tracking / Programming（录音 + 编程把表演固化成轨） SOP walkthrough for 音乐制作 / 混音.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="音乐制作 / 混音"
WORKFLOW="Tracking / Programming（录音 + 编程把表演固化成轨）"

usage() {
  cat <<EOF
tracking-programming.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./tracking-programming.sh             # interactive
  ./tracking-programming.sh --dry-run
  ./tracking-programming.sh --json
  ./tracking-programming.sh --explain
  ./tracking-programming.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "Tracking / Programming（录音 + 编程把表演固化成轨）" 工作流。

一句话: 把编曲里的乐器/人声/节拍从"虚拟/草稿"固化成真实录音轨或编程 MIDI/采样轨 —— 这一步的源头质量直接决定混音上限（"录好源头 = 混音成功一半"）。(evidence: [T03-S001])

入门 SOP 共 5 步, 失败模式自检 3 项。

相关心智模型:
  • 服务歌优先于服务技术 (serve the song): 技术、音色、个人风格全都服从于"这首歌要表达什么"——好不好的最终裁判是情绪与歌本身，不是参数表（"if it sounds good, it is good"）。
  • 减法优先 / 每个处理都要能说出理由 (less but knowing why): 默认不处理；做得太多而非太少是这一行最常见的病——加任何东西（轨/EQ/压缩/响度）之前，先确认能不能减、不加，且每一次处理都要能讲出"我为什么这么做"。

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**设置增益结构（gain staging）+ 监听**: 输入电平留足 headroom（峰值不撞 0 dBFS），确认监听/耳机能听清。跳过 → 录进削波/底噪过大，后期无法挽救。(evidence: [T03-S001], gain staging def T06)"
  "**话筒选型 + 摆位（录音轨）**: 按声源选话筒（U47 人声/SM7B 抗噪/SM57 万用乐器）并摆位，先调好房间/源头再录。跳过 → 录到房间反射/相位问题/不合适音色，混音里 EQ 救不回。(evidence: [T03-S001], 话筒 T02-S018)"
  "**录多 take（人声/独奏）+ 录 DI（吉他/贝斯）**: 同一段录多条供后续 comp；电吉他/贝斯同时录 DI 干信号留 reamp 余地。跳过 → 只有一条 take 没得挑；没 DI 后期想换音色无能为力。(evidence: [T03-S002])"
  "**编程节拍/合成（programming 轨）**: 用 step sequencer/piano roll 编鼓与合成（FL/Ableton），先按网格落 note。跳过 → 没有节奏骨架，其他声部无法对齐。(evidence: [T03-S010, T03-S015])"
  "**命名/标注/初步整理**: 每轨命名、着色、标记最佳 take，导出/保存 session。跳过 → 进编辑阶段面对一堆 \"Audio 1/Audio 2\"，效率崩塌。"
)
declare -a FAILURE_MODES=(
  "**\"we'll fix it in the mix\" 心态**: 触发原因 = 源头随便录、指望混音补救。**CLI 化暗示**: 检查项「这条 take 的音色/电平/相位是否已经接近你想要的成品？如果不是，先重录/换话筒摆位，别留给混音」。"
  "**录进削波或电平过低**: 触发原因 = 没设 gain staging，峰值撞 0 或淹在底噪里。**CLI 化暗示**: 检查项「录音峰值是否在 -6~-12 dBFS 区间？有没有红灯削波？」。"
  "**电吉他/贝斯没录 DI**: 触发原因 = 只录了过箱声，后期想换音色无 DI 可 reamp。**CLI 化暗示**: 检查项「吉他/贝斯是否同时录了 DI 干信号？」。"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "tracking-programming-walkthrough"
fi
